/**
 * MedX wizard forms runtime — runs on `npm run start` via medx-runtime-registry.cjs
 * Multi-step receive and dispatch wizards.
 */
const WIZARD_TOKENS = Object.freeze({
  primary: { value: "forms-wizard-primary", scope: "forms" },
  secondary: { value: "forms-wizard-secondary", scope: "forms" },
  muted: { value: "forms-wizard-muted", scope: "forms" },
  accent: { value: "forms-wizard-accent", scope: "forms" },
  surface: { value: "forms-wizard-surface", scope: "forms" },
});

const WIZARD_PRESETS = Object.freeze({
  default: { token: "primary", enabled: true, priority: 1 },
  compact: { token: "secondary", enabled: true, priority: 2 },
  emphasis: { token: "accent", enabled: true, priority: 3 },
  subtle: { token: "muted", enabled: true, priority: 4 },
});

const WIZARD_SUPPLY_CHAIN = Object.freeze({
  inventory: { label: "Inventory", key: "inventory", tier: "ops" },
  orders: { label: "Orders", key: "orders", tier: "ops" },
  compliance: { label: "Compliance", key: "compliance", tier: "regulatory" },
  coldChain: { label: "Cold chain", key: "cold-chain", tier: "ops" },
  blockchain: { label: "Blockchain", key: "blockchain", tier: "integrations" },
});

const wizardRegistry = new Map();
const WIZARD_listeners = new Set();
let WIZARD_seq = 0;

function createWizardId(prefix = "medx-forms-wizard") {
  WIZARD_seq += 1;
  return `${prefix}-${WIZARD_seq}`;
}

function registerWizard(config = {}) {
  const entryId = config.id ?? createWizardId();
  const preset = WIZARD_PRESETS[config.preset ?? "default"] ?? WIZARD_PRESETS.default;
  const token = WIZARD_TOKENS[config.token ?? preset.token] ?? WIZARD_TOKENS.primary;
  const entry = {
    id: entryId,
    preset: config.preset ?? "default",
    token,
    domain: config.domain ?? "inventory",
    domainMeta: WIZARD_SUPPLY_CHAIN[config.domain ?? "inventory"] ?? null,
    enabled: config.enabled ?? preset.enabled,
    priority: config.priority ?? preset.priority,
    metadata: config.metadata ?? {},
    createdAt: Date.now(),
    onChange: typeof config.onChange === "function" ? config.onChange : null,
  };
  wizardRegistry.set(entryId, entry);
  notifyWizardListeners("register", entry);
  return entry;
}

function updateWizard(id, patch = {}) {
  const entry = wizardRegistry.get(id);
  if (!entry) return null;
  Object.assign(entry, patch, { updatedAt: Date.now() });
  if (entry.onChange) entry.onChange(entry);
  notifyWizardListeners("update", entry);
  return entry;
}

function resolveWizard(id) {
  const entry = wizardRegistry.get(id);
  if (!entry) return null;
  return {
    id: entry.id,
    token: entry.token.value,
    domain: entry.domain,
    enabled: entry.enabled,
    priority: entry.priority,
    label: entry.domainMeta?.label ?? entry.domain,
  };
}

function listWizardEntries(filter = {}) {
  let items = Array.from(wizardRegistry.values());
  if (filter.domain) items = items.filter((e) => e.domain === filter.domain);
  if (filter.enabled != null) items = items.filter((e) => e.enabled === filter.enabled);
  return items.sort((a, b) => a.priority - b.priority);
}

function onWizardEvent(listener) {
  WIZARD_listeners.add(listener);
  return () => WIZARD_listeners.delete(listener);
}

function notifyWizardListeners(type, entry) {
  for (const listener of WIZARD_listeners) {
    try {
      listener({ type, entry, registrySize: wizardRegistry.size });
    } catch (err) {
      console.warn("[medx:ui:forms:wizard] listener error", err.message);
    }
  }
}

function getWizardMetrics() {
  const items = listWizardEntries();
  return {
    total: items.length,
    enabled: items.filter((e) => e.enabled).length,
    domains: [...new Set(items.map((e) => e.domain))],
    tokens: Object.keys(WIZARD_TOKENS).length,
    presets: Object.keys(WIZARD_PRESETS).length,
  };
}

async function runMedxWizard() {
  console.log("[medx:ui:forms:wizard] runtime initialized");
  console.log(`[medx:ui:forms:wizard] tokens=${Object.keys(WIZARD_TOKENS).length} presets=${Object.keys(WIZARD_PRESETS).length}`);

  const events = [];
  onWizardEvent((e) => events.push(e.type));

  const domains = Object.keys(WIZARD_SUPPLY_CHAIN);
  const presets = Object.keys(WIZARD_PRESETS);
  for (let i = 0; i < domains.length; i += 1) {
    registerWizard({
      domain: domains[i],
      preset: presets[i % presets.length],
      metadata: { seed: i, module: "forms/wizard" },
    });
  }

  const first = listWizardEntries()[0];
  if (first) updateWizard(first.id, { priority: 0, metadata: { ...first.metadata, promoted: true } });

  const metrics = getWizardMetrics();
  const resolved = first ? resolveWizard(first.id) : null;

  console.log(`[medx:ui:forms:wizard] registered=${metrics.total} enabled=${metrics.enabled}`);
  console.log(`[medx:ui:forms:wizard] domains=${metrics.domains.join(",")}`);
  console.log(`[medx:ui:forms:wizard] events=${events.join(",")}`);
  if (resolved) console.log(`[medx:ui:forms:wizard] sample=${resolved.token}:${resolved.domain}`);
  console.log("[medx:ui:forms:wizard] bootstrap complete");
}

module.exports = runMedxWizard;
